// From SkiaEntry - CJK composition handling
public class CJKInputHandler
{
    private string _compositionText = string.Empty;
    private List<string> _candidates = new();
    private int _selectedCandidate = 0;

    public void HandleCompositionUpdate(string composition, string[] candidates)
    {
        _compositionText = composition;
        _candidates = candidates?.ToList() ?? new();
        _selectedCandidate = 0;

        // Show candidate window
        ShowCandidateWindow();
    }

    public void HandleCandidateSelection(int index)
    {
        if (index >= 0 && index < _candidates.Count)
        {
            _selectedCandidate = index;
            CommitText(_candidates[index]);
            ClearComposition();
        }
    }

    private void ShowCandidateWindow()
    {
        if (_candidates.Count == 0)
            return;

        var candidateWindow = new CandidateWindow
        {
            Candidates = _candidates,
            SelectedIndex = _selectedCandidate,
            Position = GetCursorScreenPosition()
        };

        candidateWindow.Show();
    }
}
