public void DrawVerticalText(SKCanvas canvas, string text, float x, float y)
{
    using var paint = new SKPaint
    {
        Typeface = GetCJKFont(CJKLanguage.Japanese),
        TextSize = 16,
        IsAntialias = true
    };

    float currentY = y;
    foreach (var c in text)
    {
        canvas.DrawText(c.ToString(), x, currentY, paint);
        currentY += paint.TextSize * 1.2f; // Line height
    }
}
