// From SkiaEntry - CJK composition handling
public class CJKInputHandler
{
    private string _compositionText = string.Empty;
    private List<string> _candidates = new();
    private int _selectedCandidate = 0;

    public void HandleCompositionUpdate(string composition, string[] candidates)
    {
        _compositionText = composition;
        _candidates = candidates?.ToList() ?? new();
        _selectedCandidate = 0;

        // Show candidate window
        ShowCandidateWindow();
    }

    public void HandleCandidateSelection(int index)
    {
        if (index >= 0 && index < _candidates.Count)
        {
            _selectedCandidate = index;
            CommitText(_candidates[index]);
            ClearComposition();
        }
    }

    private void ShowCandidateWindow()
    {
        if (_candidates.Count == 0)
            return;

        var candidateWindow = new CandidateWindow
        {
            Candidates = _candidates,
            SelectedIndex = _selectedCandidate,
            Position = GetCursorScreenPosition()
        };

        candidateWindow.Show();
    }
}
```

## Candidate Window Rendering

CJK input requires displaying candidate characters:

```csharp
public class CandidateWindow : SkiaView
{
    public List<string> Candidates { get; set; }
    public int SelectedIndex { get; set; }

    protected override void OnDraw(SKCanvas canvas)
    {
        // Draw background
        using var bgPaint = new SKPaint
        {
            Color = SKColors.White,
            Style = SKPaintStyle.Fill
        };
        canvas.DrawRoundRect(Bounds.ToSKRect(), 4, 4, bgPaint);

        // Draw border
        using var borderPaint = new SKPaint
        {
            Color = SKColors.Gray,
            Style = SKPaintStyle.Stroke,
            StrokeWidth = 1
        };
        canvas.DrawRoundRect(Bounds.ToSKRect(), 4, 4, borderPaint);

        // Draw candidates
        float y = 10;
        for (int i = 0; i < Candidates.Count; i++)
        {
            var isSelected = i == SelectedIndex;

            // Highlight selected candidate
            if (isSelected)
            {
                using var highlightPaint = new SKPaint
                {
                    Color = new SKColor(200, 220, 255),
                    Style = SKPaintStyle.Fill
                };
                var highlightRect = new SKRect(5, y - 2, Width - 5, y + 22);
                canvas.DrawRoundRect(highlightRect, 2, 2, highlightPaint);
            }

            // Draw candidate number
            using var numberPaint = new SKPaint
            {
                Color = SKColors.Gray,
                TextSize = 14,
                IsAntialias = true
            };
            canvas.DrawText($"{i + 1}.", 10, y + 16, numberPaint);

            // Draw candidate text
            using var textPaint = new SKPaint
            {
                Color = isSelected ? SKColors.Black : SKColors.DarkGray,
                TextSize = 16,
                IsAntialias = true,
                Typeface = GetCJKTypeface()
            };
            canvas.DrawText(Candidates[i], 35, y + 16, textPaint);

            y += 25;
        }
    }

    private SKTypeface GetCJKTypeface()
    {
        return SKTypeface.FromFamilyName("Noto Sans CJK SC") ??
               SKTypeface.FromFamilyName("WenQuanYi Micro Hei") ??
               SKTypeface.FromFamilyName("Noto Sans");
    }
}
```

## Japanese Kana Conversion

Japanese input requires converting between romaji, hiragana, and kanji:

```csharp
public class JapaneseInputConverter
{
    private readonly Dictionary<string, string> _romajiToHiragana = new()
    {
        { "a", "あ" }, { "i", "い" }, { "u", "う" }, { "e", "え" }, { "o", "お" },
        { "ka", "か" }, { "ki", "き" }, { "ku", "く" }, { "ke", "け" }, { "ko", "こ" },
        { "sa", "さ" }, { "shi", "し" }, { "su", "す" }, { "se", "せ" }, { "so", "そ" },
        { "ta", "た" }, { "chi", "ち" }, { "tsu", "つ" }, { "te", "て" }, { "to", "と" },
        { "na", "な" }, { "ni", "に" }, { "nu", "ぬ" }, { "ne", "ね" }, { "no", "の" },
        // ... more mappings
    };

    public string ConvertRomajiToHiragana(string romaji)
    {
        var result = new StringBuilder();
        var buffer = new StringBuilder();

        foreach (var c in romaji)
        {
            buffer.Append(c);

            // Try to match longest possible sequence
            var matched = false;
            for (int len = buffer.Length; len > 0; len--)
            {
                var substring = buffer.ToString().Substring(buffer.Length - len);
                if (_romajiToHiragana.TryGetValue(substring, out var hiragana))
                {
                    // Keep unmatched prefix
                    if (buffer.Length > len)
                    {
                        result.Append(buffer.ToString().Substring(0, buffer.Length - len));
                    }
                    result.Append(hiragana);
                    buffer.Clear();
                    matched = true;
                    break;
                }
            }
        }

        // Append remaining buffer
        result.Append(buffer);
        return result.ToString();
    }
}

// Example:
var converter = new JapaneseInputConverter();
var hiragana = converter.ConvertRomajiToHiragana("konnichiwa");
// Result: "こんにちわ"
```

## Korean Hangul Composition

Korean uses jamo (consonants and vowels) that combine into syllables:

```csharp
public class HangulComposer
{
    private const int HangulBase = 0xAC00;
    private const int InitialCount = 19;
    private const int MedialCount = 21;
    private const int FinalCount = 28;

    public string ComposeHangul(char initial, char medial, char final = '\0')
    {
        // Convert jamo to indices
        int initialIndex = GetInitialIndex(initial);
        int medialIndex = GetMedialIndex(medial);
        int finalIndex = final == '\0' ? 0 : GetFinalIndex(final) + 1;

        if (initialIndex == -1 || medialIndex == -1 || finalIndex == -1)
            return string.Empty;

        // Calculate syllable codepoint
        int syllable = HangulBase + 
                      (initialIndex * MedialCount * FinalCount) +
                      (medialIndex * FinalCount) +
                      finalIndex;

        return char.ConvertFromUtf32(syllable);
    }

    private int GetInitialIndex(char c)
    {
        // ㄱ ㄲ ㄴ ㄷ ㄸ ㄹ ㅁ ㅂ ㅃ ㅅ ㅆ ㅇ ㅈ ㅉ ㅊ ㅋ ㅌ ㅍ ㅎ
        return c switch
        {
            'ㄱ' => 0, 'ㄲ' => 1, 'ㄴ' => 2, 'ㄷ' => 3, 'ㄸ' => 4,
            'ㄹ' => 5, 'ㅁ' => 6, 'ㅂ' => 7, 'ㅃ' => 8, 'ㅅ' => 9,
            'ㅆ' => 10, 'ㅇ' => 11, 'ㅈ' => 12, 'ㅉ' => 13, 'ㅊ' => 14,
            'ㅋ' => 15, 'ㅌ' => 16, 'ㅍ' => 17, 'ㅎ' => 18,
            _ => -1
        };
    }

    private int GetMedialIndex(char c)
    {
        // ㅏ ㅐ ㅑ ㅒ ㅓ ㅔ ㅕ ㅖ ㅗ ㅘ ㅙ ㅚ ㅛ ㅜ ㅝ ㅞ ㅟ ㅠ ㅡ ㅢ ㅣ
        return c switch
        {
            'ㅏ' => 0, 'ㅐ' => 1, 'ㅑ' => 2, 'ㅒ' => 3, 'ㅓ' => 4,
            'ㅔ' => 5, 'ㅕ' => 6, 'ㅖ' => 7, 'ㅗ' => 8, 'ㅘ' => 9,
            'ㅙ' => 10, 'ㅚ' => 11, 'ㅛ' => 12, 'ㅜ' => 13, 'ㅝ' => 14,
            'ㅞ' => 15, 'ㅟ' => 16, 'ㅠ' => 17, 'ㅡ' => 18, 'ㅢ' => 19,
            'ㅣ' => 20,
            _ => -1
        };
    }

    private int GetFinalIndex(char c)
    {
        // (none) ㄱ ㄲ ㄳ ㄴ ㄵ ㄶ ㄷ ㄹ ㄺ ㄻ ㄼ ㄽ ㄾ ㄿ ㅀ ㅁ ㅂ ㅄ ㅅ ㅆ ㅇ ㅈ ㅊ ㅋ ㅌ ㅍ ㅎ
        return c switch
        {
            'ㄱ' => 0, 'ㄲ' => 1, 'ㄳ' => 2, 'ㄴ' => 3, 'ㄵ' => 4,
            'ㄶ' => 5, 'ㄷ' => 6, 'ㄹ' => 7, 'ㄺ' => 8, 'ㄻ' => 9,
            'ㄼ' => 10, 'ㄽ' => 11, 'ㄾ' => 12, 'ㄿ' => 13, 'ㅀ' => 14,
            'ㅁ' => 15, 'ㅂ' => 16, 'ㅄ' => 17, 'ㅅ' => 18, 'ㅆ' => 19,
            'ㅇ' => 20, 'ㅈ' => 21, 'ㅊ' => 22, 'ㅋ' => 23, 'ㅌ' => 24,
            'ㅍ' => 25, 'ㅎ' => 26,
            _ => -1
        };
    }
}

// Example:
var composer = new HangulComposer();
var syllable = composer.ComposeHangul('ㄱ', 'ㅏ', 'ㅇ');
// Result: "강"
```

## CJK Font Selection

Different CJK languages prefer different glyph variants:

```csharp
public class CJKFontSelector
{
    public SKTypeface GetCJKFont(CJKLanguage language)
    {
        return language switch
        {
            CJKLanguage.SimplifiedChinese => 
                SKTypeface.FromFamilyName("Noto Sans CJK SC") ??
                SKTypeface.FromFamilyName("WenQuanYi Micro Hei"),

            CJKLanguage.TraditionalChinese =>
                SKTypeface.FromFamilyName("Noto Sans CJK TC") ??
                SKTypeface.FromFamilyName("WenQuanYi Micro Hei"),

            CJKLanguage.Japanese =>
                SKTypeface.FromFamilyName("Noto Sans CJK JP") ??
                SKTypeface.FromFamilyName("IPAGothic"),

            CJKLanguage.Korean =>
                SKTypeface.FromFamilyName("Noto Sans CJK KR") ??
                SKTypeface.FromFamilyName("Nanum Gothic"),

            _ => SKTypeface.FromFamilyName("Noto Sans CJK SC")
        };
    }
}

public enum CJKLanguage
{
    SimplifiedChinese,
    TraditionalChinese,
    Japanese,
    Korean
}
